  /**
   * Enable a public link for a file or a directory.
   * @date 2/19/2024 - 5:13:57 AM
   *
   * @public
   * @async
   * @param {{
   * 		type: "file" | "directory"
   * 		uuid: string
   * 		onProgress?: ProgressWithTotalCallback
   * 	}} param0
   * @param {("file" | "directory")} param0.type
   * @param {string} param0.uuid
   * @param {ProgressWithTotalCallback} param0.onProgress
   * @returns {Promise<string>}
   */
  async enablePublicLink({ type, uuid, onProgress }) {
    const linkUUID = await uuidv4();
    if (type === "directory") {
      const [tree, key] = await Promise.all([
        this.getDirectoryTree({
          uuid
        }),
        this.sdk.getWorker().crypto.utils.generateEncryptionKey("metadata")
      ]);
      const linkKeyEncrypted = await this.sdk.getWorker().crypto.encrypt.metadata({
        metadata: key
      });
      let done = 0;
      const promises = [];
      const total = Object.keys(tree).length;
      for (const entry in tree) {
        const item = tree[entry];
        if (!item || item.type === "file" && item.key.length === 0) {
          continue;
        }
        const itemNameNormalized = item.name.toLowerCase().trim();
        if (itemNameNormalized.startsWith("cannot_decrypt_") && itemNameNormalized.endsWith(`_${item.uuid}`)) {
          continue;
        }
        promises.push(new Promise((resolve, reject) => {
          this.addItemToDirectoryPublicLink({
            uuid: item.uuid,
            parent: item.parent,
            linkUUID,
            type: item.type === "directory" ? "folder" : "file",
            expiration: "never",
            linkKeyEncrypted,
            metadata: item.type === "directory" ? {
              name: item.name
            } : {
              name: item.name,
              size: item.size,
              mime: item.mime,
              lastModified: item.lastModified,
              key: item.key,
              creation: item.creation,
              hash: item.hash
            }
          }).then(() => {
            done += 1;
            if (onProgress) {
              onProgress(done, total);
            }
            resolve();
          }).catch(reject);
        }));
      }
      await promiseAllChunked(promises);
      return linkUUID;
    }
    await this.sdk.api(3).file().link().edit({
      uuid: linkUUID,
      fileUUID: uuid,
      expiration: "never",
      password: "empty",
      passwordHashed: await this.sdk.getWorker().crypto.utils.hashFn({
        input: "empty"
      }),
      downloadBtn: true,
      type: "enable",
      salt: await this.sdk.getWorker().crypto.utils.generateRandomHexString(256)
    });
    return linkUUID;
  }
